mapper.select:
/* [SQL_ID:UserMapper.selectList]*/ SELECT ROW_NUMBER() OVER() AS RN , COUNT(1) OVER() AS TOTAL_COUNT , A.* FROM ( SELECT A.USER_ID , A.USER_NAME , A.USER_EMAIL , A.USER_STATUS , A.LOGIN_FAIL_COUNT , A.CREATED_BY , TO_CHAR(A.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS CREATED_AT FROM SYS_USER A
AND (A.USER_ID LIKE '%' || #{searchText} || '%' OR A.USER_NAME LIKE '%' || #{searchText} || '%')
AND A.USER_ID LIKE '%' || #{searchText} || '%'
AND A.USER_NAME LIKE '%' || #{searchText} || '%'
ORDER BY A.USER_ID ASC ) A
LIMIT #{pageSize} OFFSET #{offset}

mapper.insert:
/* [SQL_ID:UserMapper.insert]*/
INSERT INTO SYS_USER (
      USER_ID
    , USER_PASSWORD
    , USER_NAME
    , USER_EMAIL
    , CREATED_BY
    , UPDATED_BY
) VALUES (
      #{userId}
    , #{userPassword}
    , #{userName}
    , #{userEmail}
    , #{createdBy}
    , #{updatedBy}
)

mapper.update:
/* [SQL_ID:UserMapper.update]*/
UPDATE SYS_USER

      USER_NAME     = #{userName}
    , USER_EMAIL    = #{userEmail}
    , UPDATED_BY    = #{updatedBy}
    , UPDATED_AT    = NOW()


    AND USER_ID = #{userId}
